  'blog_integration_base',
  '1.0',
  E'/* === TOKEN SYSTEM === */\n:root {\n  color-scheme: light;\n  --primary:       {{PRIMARY}};\n  --primary-2:     {{PRIMARY_2}};\n  --primary-soft:  {{PRIMARY_SOFT}};\n  --primary-glow:  {{PRIMARY_GLOW}};\n  --primary-rgb:   {{PRIMARY_RGB}};\n  --accent:        {{ACCENT}};\n  --accent-2:      {{ACCENT_2}};\n  --accent-soft:   {{ACCENT_SOFT}};\n  --accent-rgb:    {{ACCENT_RGB}};\n  --cream:        #FEF9F3;\n  --paper:        #FFFDFC;\n  --paper-2:      #F7F3EC;\n  --ink:          {{INK}};\n  --muted:        #686760;\n  --soft:         #929087;\n  --line:         rgba(44, 44, 42, 0.13);\n  --line-strong:  {{LINE_STRONG}};\n  --success-soft: #EDF8F1;\n  --warn:         #D85A30;\n  --warn-soft:    #FFF0EA;\n  --warn-line:    #F4C4B3;\n  --white:        #FFFFFF;\n  --step--2: clamp(0.72rem, 0.70rem + 0.08vw, 0.78rem);\n  --step--1: clamp(0.82rem, 0.78rem + 0.17vw, 0.94rem);\n  --step-0:  clamp(0.96rem, 0.90rem + 0.26vw, 1.06rem);\n  --step-1:  clamp(1.08rem, 0.99rem + 0.45vw, 1.30rem);\n  --step-2:  clamp(1.32rem, 1.10rem + 0.95vw, 1.75rem);\n  --step-3:  clamp(1.65rem, 1.29rem + 1.55vw, 2.45rem);\n  --step-4:  clamp(2.05rem, 1.50rem + 2.35vw, 3.45rem);\n  --step-5:  clamp(2.55rem, 1.72rem + 3.60vw, 4.75rem);\n  --space-1: clamp(0.35rem, 0.31rem + 0.18vw, 0.50rem);\n  --space-2: clamp(0.65rem, 0.55rem + 0.42vw, 0.95rem);\n  --space-3: clamp(0.95rem, 0.78rem + 0.75vw, 1.45rem);\n  --space-4: clamp(1.25rem, 1.00rem + 1.05vw, 2.00rem);\n  --space-5: clamp(1.70rem, 1.28rem + 1.75vw, 3.00rem);\n  --space-6: clamp(2.20rem, 1.62rem + 2.45vw, 4.25rem);\n  --space-7: clamp(3.00rem, 2.15rem + 3.60vw, 6.25rem);\n  --space-8: clamp(4.00rem, 2.75rem + 5.40vw, 9.00rem);\n  --radius-sm:   0.85rem;\n  --radius-md:   1.15rem;\n  --radius-lg:   1.65rem;\n  --radius-xl:   2.15rem;\n  --radius-pill: 999px;\n  --shadow-sm: 0 0.6rem 1.6rem rgba(19, 46, 96, 0.08);\n  --shadow-md: 0 1.1rem 2.8rem rgba(19, 46, 96, 0.12);\n  --shadow-lg: 0 2rem 5rem rgba(19, 46, 96, 0.16);\n  --content: min(100% - 2rem, 72rem);\n  --visual:  min(100% - 1rem, 78rem);\n  --wide:    min(100% - 1rem, 90rem);\n}\n\n* { box-sizing: border-box; }\n\nhtml { scroll-behavior: smooth; background: var(--cream); }\n\nbody {\n  margin: 0;\n  min-height: 100vh;\n  font-family: '\''DM Sans'\'', system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\n  font-size: var(--step-0);\n  line-height: 1.7;\n  color: var(--ink);\n  background:\n    radial-gradient(circle at top left, var(--primary-glow), transparent 24rem),\n    radial-gradient(circle at 90% 8rem, var(--primary-glow), transparent 22rem),\n    linear-gradient(180deg, #FFFDF8 0%, var(--cream) 26rem, var(--accent-soft) 100%);\n  -webkit-text-size-adjust: 100%;\n  text-rendering: optimizeLegibility;\n}\n\nbody::before {\n  content: "";\n  position: fixed;\n  inset: 0;\n  pointer-events: none;\n  z-index: -1;\n  opacity: 0.55;\n  background-image:\n    linear-gradient(rgba(var(--primary-rgb), 0.04) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(var(--primary-rgb), 0.04) 1px, transparent 1px);\n  background-size: 2.75rem 2.75rem;\n  mask-image: linear-gradient(to bottom, black, transparent 78%);\n}\n\n@supports (animation-timeline: scroll()) {\n  body::after {\n    content: "";\n    position: fixed;\n    top: 0;\n    left: 0;\n    height: 0.25rem;\n    width: 100%;\n    transform-origin: 0 50%;\n    transform: scaleX(0);\n    background: linear-gradient(90deg, var(--accent), var(--primary-2));\n    z-index: 100;\n    animation: read-progress linear both;\n    animation-timeline: scroll(root);\n  }\n  @keyframes read-progress { to { transform: scaleX(1); } }\n}\n\na { color: var(--primary-2); }\n\na:focus-visible, button:focus-visible {\n  outline: 3px solid rgba(var(--accent-rgb), 0.45);\n  outline-offset: 4px;\n  border-radius: 0.35rem;\n}\n\n.skip-link {\n  position: fixed;\n  left: 1rem;\n  top: 1rem;\n  z-index: 999;\n  transform: translateY(-160%);\n  padding: 0.75rem 1rem;\n  border-radius: var(--radius-pill);\n  background: var(--primary);\n  color: var(--white);\n  text-decoration: none;\n  box-shadow: var(--shadow-md);\n}\n.skip-link:focus { transform: translateY(0); }\n\n.blog-wrap {\n  width: 100%;\n  margin: 0 auto;\n  padding: var(--space-3) 0 var(--space-8);\n  counter-reset: section;\n}\n\n.card-wrap {\n  width: var(--wide);\n  margin: var(--space-5) auto;\n}\n\n.infographic-card, .prose {\n  position: relative;\n  overflow: clip;\n  border: 1px solid var(--line);\n  background:\n    linear-gradient(180deg, rgba(255, 255, 255, 0.92), rgba(255, 252, 248, 0.94)),\n    var(--paper);\n  box-shadow: var(--shadow-sm);\n}\n\n.infographic-card {\n  border-radius: var(--radius-xl);\n  padding: var(--space-4);\n}\n\n.prose {\n  width: var(--content);\n  margin: var(--space-4) auto;\n  padding: var(--space-5) clamp(1.15rem, 4.5vw, 3.25rem);\n  border-radius: var(--radius-lg);\n}\n\n.prose + .prose { margin-top: var(--space-4); }\n\n.prose::before {\n  content: "";\n  position: absolute;\n  inset: 0 auto 0 0;\n  width: 0.28rem;\n  background: linear-gradient(180deg, var(--accent), rgba(var(--accent-rgb), 0.06));\n  opacity: 0.62;\n}\n\n.prose h2 {\n  counter-increment: section;\n  margin: 0 0 var(--space-4);\n  font-family: '\''DM Sans'\'', system-ui, sans-serif;\n  font-size: var(--step-4);\n  font-weight: 600;\n  line-height: 1.15;\n  letter-spacing: -0.02em;\n  color: var(--ink);\n  text-wrap: balance;\n}\n\n.prose h2::before {\n  content: "Section " counter(section, decimal-leading-zero);\n  display: block;\n  width: fit-content;\n  margin-bottom: var(--space-2);\n  padding: 0.35rem 0.75rem;\n  border: 1px solid rgba(var(--accent-rgb), 0.25);\n  border-radius: var(--radius-pill);\n  background: var(--accent-soft);\n  color: var(--accent);\n  font-family: '\''DM Sans'\'', system-ui, sans-serif;\n  font-size: var(--step--2);\n  font-weight: 700;\n  line-height: 1;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n}\n\n.prose h3 {\n  margin: var(--space-6) 0 var(--space-3);\n  font-family: '\''DM Sans'\'', system-ui, sans-serif;\n  font-size: var(--step-2);\n  font-weight: 600;\n  line-height: 1.3;\n  letter-spacing: -0.01em;\n  color: var(--primary);\n  text-wrap: balance;\n}\n\n.prose p {\n  margin: 0 0 var(--space-4);\n  color: color-mix(in srgb, var(--ink) 86%, var(--muted));\n  font-size: var(--step-0);\n  line-height: 1.82;\n}\n\n.prose p:first-of-type {\n  font-size: clamp(1.02rem, 0.95rem + 0.32vw, 1.16rem);\n  color: var(--ink);\n}\n\n.prose p:last-child { margin-bottom: 0; }\n\n.prose ul {\n  display: grid;\n  gap: var(--space-2);\n  margin: 0 0 var(--space-4);\n  padding: 0;\n  list-style: none;\n}\n\n.prose li {\n  position: relative;\n  padding: 1rem 1rem 1rem 3rem;\n  border: 1px solid var(--line);\n  border-radius: var(--radius-md);\n  background: rgba(255, 255, 255, 0.62);\n  color: var(--ink);\n  box-shadow: 0 0.35rem 1rem rgba(19, 46, 96, 0.045);\n}\n\n.prose li::before {\n  content: "";\n  position: absolute;\n  left: 1rem;\n  top: 1.3rem;\n  width: 0.72rem;\n  height: 0.72rem;\n  border-radius: 50%;\n  background: radial-gradient(circle, var(--accent) 0 36%, var(--accent-soft) 38% 100%);\n  box-shadow: 0 0 0 0.32rem rgba(var(--accent-rgb), 0.12);\n}\n\n.prose a {\n  color: var(--accent);\n  font-weight: 700;\n  text-decoration-thickness: 0.09em;\n  text-decoration-color: rgba(var(--accent-rgb), 0.35);\n  text-underline-offset: 0.18em;\n}\n\n.prose a:hover {\n  color: var(--primary-2);\n  text-decoration-color: rgba(var(--primary-rgb), 0.55);\n}\n\n.table-scroll {\n  overflow-x: auto;\n  -webkit-overflow-scrolling: touch;\n  border: 1px solid var(--line);\n  border-radius: var(--radius-lg);\n  background: var(--white);\n  margin-bottom: var(--space-4);\n}\n\n.compare-table {\n  width: 100%;\n  border-collapse: collapse;\n  font-size: var(--step--1);\n}\n\n.compare-table th {\n  padding: 1rem;\n  color: var(--white);\n  background: linear-gradient(135deg, var(--primary), var(--primary-2));\n  text-align: left;\n  font-size: var(--step--1);\n  line-height: 1.25;\n}\n\n.compare-table td {\n  padding: 1rem;\n  border-bottom: 1px solid var(--line);\n  color: var(--ink);\n  vertical-align: top;\n  line-height: 1.62;\n}\n\n.compare-table tr:nth-child(even) td { background: rgba(var(--primary-rgb), 0.05); }\n.compare-table tr:last-child td { border-bottom: none; }\n\n.header {\n  position: relative;\n  isolation: isolate;\n  display: grid;\n  place-items: center;\n  min-height: clamp(27rem, 70svh, 46rem);\n  padding: var(--space-6) clamp(1rem, 5vw, 4.5rem);\n  text-align: center;\n  border-radius: calc(var(--radius-xl) - 0.35rem);\n  background:\n    radial-gradient(circle at 50% 4rem, rgba(255, 255, 255, 0.92), transparent 12rem),\n    radial-gradient(circle at 12% 20%, rgba(var(--accent-rgb), 0.22), transparent 13rem),\n    radial-gradient(circle at 86% 18%, rgba(var(--primary-rgb), 0.21), transparent 16rem),\n    linear-gradient(135deg, var(--accent-soft), var(--primary-soft) 45%, var(--paper) 100%);\n  overflow: hidden;\n}\n\n.header::before, .header::after {\n  content: "";\n  position: absolute;\n  z-index: -1;\n  border-radius: 999px;\n  opacity: 0.5;\n  filter: blur(0.1rem);\n}\n\n.header::before {\n  width: 12rem; height: 12rem;\n  left: -4.5rem; bottom: -3.5rem;\n  background: repeating-linear-gradient(45deg, rgba(var(--accent-rgb), 0.12) 0 0.45rem, transparent 0.45rem 0.9rem);\n}\n\n.header::after {\n  width: 15rem; height: 15rem;\n  right: -5.5rem; top: -4rem;\n  border: 1.2rem solid rgba(var(--primary-rgb), 0.08);\n}\n\n.header-eyebrow {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  gap: 0.65rem;\n  width: fit-content;\n  margin: 0 auto var(--space-3);\n  padding: 0.55rem 0.9rem;\n  border: 1px solid rgba(var(--primary-rgb), 0.16);\n  border-radius: var(--radius-pill);\n  background: rgba(255, 255, 255, 0.75);\n  color: var(--primary);\n  font-size: var(--step--2);\n  font-weight: 800;\n  letter-spacing: 0.14em;\n  text-transform: uppercase;\n  box-shadow: 0 0.6rem 1.5rem rgba(var(--primary-rgb), 0.07);\n}\n\n.header h1 {\n  max-width: 18ch;\n  margin: 0 auto var(--space-3);\n  font-family: '\''DM Serif Display'\'', Georgia, serif;\n  font-size: var(--step-5);\n  font-weight: 400;\n  line-height: 0.92;\n  letter-spacing: -0.06em;\n  color: var(--primary);\n  text-wrap: balance;\n}\n\n.header h1 em { font-style: italic; color: var(--accent); }\n\n.header-sub {\n  max-width: 38rem;\n  margin: 0 auto;\n  color: var(--muted);\n  font-size: var(--step-1);\n  line-height: 1.65;\n  text-wrap: pretty;\n}\n\n.header-meta {\n  margin-top: var(--space-3);\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n  gap: 0.6rem;\n  font-size: var(--step--2);\n  color: var(--soft);\n}\n\n.header-meta span {\n  padding: 0.35rem 0.85rem;\n  border-radius: var(--radius-pill);\n  background: rgba(255, 255, 255, 0.8);\n  border: 1px solid rgba(var(--primary-rgb), 0.12);\n}\n\n.cta-card {\n  width: var(--content);\n  margin: var(--space-5) auto;\n  padding: var(--space-5) var(--space-4);\n  border: 1px solid rgba(var(--primary-rgb), 0.28);\n  border-radius: var(--radius-xl);\n  background:\n    radial-gradient(circle at 18% 18%, rgba(var(--accent-rgb), 0.18), transparent 13rem),\n    radial-gradient(circle at 90% 12%, rgba(var(--primary-rgb), 0.16), transparent 16rem),\n    linear-gradient(135deg, #FFFFFF, var(--primary-soft));\n  text-align: center;\n  box-shadow: 0 0.55rem 1.5rem rgba(var(--primary-rgb), 0.1);\n}\n\n.cta-card h2 {\n  max-width: 22ch;\n  margin: 0 auto var(--space-3);\n  font-family: '\''DM Serif Display'\'', Georgia, serif;\n  font-size: var(--step-4);\n  font-weight: 400;\n  line-height: 1.1;\n  letter-spacing: -0.045em;\n  color: var(--primary);\n  text-wrap: balance;\n}\n\n.cta-card h2 em { font-style: italic; color: var(--accent); }\n\n.cta-card p {\n  max-width: 44rem;\n  margin: 0 auto var(--space-4);\n  color: var(--muted);\n  font-size: var(--step-0);\n  line-height: 1.72;\n}\n\n.cta-pills {\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n  gap: 0.6rem;\n}\n\n.cta-pill {\n  display: inline-flex;\n  align-items: center;\n  min-height: 2.25rem;\n  padding: 0.42rem 0.85rem;\n  border: 1px solid rgba(var(--primary-rgb), 0.28);\n  border-radius: var(--radius-pill);\n  background: rgba(255, 255, 255, 0.9);\n  color: var(--primary);\n  font-size: var(--step--2);\n  font-weight: 800;\n  letter-spacing: 0.09em;\n  text-transform: uppercase;\n  text-decoration: none;\n  box-shadow: 0 0.5rem 1.15rem rgba(var(--primary-rgb), 0.1);\n}\n\n.cta-pill:hover { background: var(--primary); color: var(--white); }\n\n.faq-item {\n  border-bottom: 1px solid var(--line);\n  padding: var(--space-3) 0;\n}\n.faq-item:last-child { border-bottom: none; }\n.faq-q {\n  font-weight: 700;\n  color: var(--primary);\n  margin: 0 0 var(--space-2);\n  font-size: var(--step-0);\n}\n.faq-a {\n  margin: 0;\n  color: color-mix(in srgb, var(--ink) 86%, var(--muted));\n  line-height: 1.82;\n}\n\n.callout-text {\n  margin: var(--space-4) 0;\n  padding: var(--space-3) var(--space-4);\n  border-left: 4px solid var(--accent);\n  background: rgba(var(--accent-rgb), 0.04);\n  color: var(--ink);\n  font-style: italic;\n  line-height: 1.72;\n}\n\n@media (min-width: 42rem) {\n  .infographic-card { padding: var(--space-5); }\n}\n\n@media (min-width: 58rem) {\n  .card-wrap { margin-block: var(--space-6); }\n  .prose { margin-block: var(--space-5); }\n  .prose:hover, .infographic-card:hover { box-shadow: var(--shadow-md); transform: translateY(-1px); }\n  .prose, .infographic-card { transition: box-shadow 180ms ease, transform 180ms ease; }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  *, *::before, *::after {\n    animation-duration: 0.001ms !important;\n    animation-iteration-count: 1 !important;\n    scroll-behavior: auto !important;\n    transition-duration: 0.001ms !important;\n  }\n}\n\n@media print {\n  body { background: #fff; }\n  body::before, body::after, .skip-link { display: none !important; }\n  .blog-wrap, .prose, .card-wrap, .infographic-card, .cta-card {\n    width: auto; max-width: none; margin: 0 0 1.25rem;\n    padding: 0; border: 0; box-shadow: none; background: #fff;\n  }\n  .header { min-height: 0; padding: 0 0 1rem; background: #fff; }\n}'::text,
  ARRAY['PRIMARY', 'PRIMARY_2', 'PRIMARY_SOFT', 'PRIMARY_GLOW', 'PRIMARY_RGB', 'ACCENT', 'ACCENT_2', 'ACCENT_SOFT', 'ACCENT_RGB', 'INK', 'LINE_STRONG']
